/// <summary>
/// 
/// </summary>
/// <param name = "defaultDimension"></param>
/// <param name = "dimName"></param>
/// <returns></returns>
public static str getDimensionDisplayValue(RecId defaultDimension, Name dimName)
{
    DimensionAttributeValue dimAttributeValue;
    DefaultDimensionView dimensionView;
    DimensionAttribute dimensionAttribute;

    select firstOnly dimensionView
        where dimensionView.DefaultDimension == defaultDimension
        join dimensionAttribute
        where dimensionView.Name == dimName;

    select * from dimAttributeValue where dimAttributeValue.DisplayValue == dimensionView.DisplayValue;

    return dimAttributeValue.getName();
}

public static str getDimensionDisplayValueCodeOnlyETG(RecId defaultDimension, Name dimName)
{
    DefaultDimensionView dimensionView;

    select firstOnly DisplayValue from dimensionView
        where dimensionView.DefaultDimension == defaultDimension
        && dimensionView.Name == dimName;

    return dimensionView.DisplayValue;
}
